/* Reserve fixed height for the deals grid before JS injects cards. Prevents the
   classic "main screen jumps when deals load" CLS. Skeleton cards live in this
   reserved box and are removed (not collapsed) once real deals render. */
.live-deals-grid {
  min-height: 520px;
  position: relative;
}
.live-deals-grid.is-populated { min-height: 0; }
@media (max-width: 600px) { .live-deals-grid { min-height: 1180px; } }
@media (min-width: 601px) and (max-width: 900px) { .live-deals-grid { min-height: 760px; } }

/* Skeleton placeholder cards shown inside the reserved grid box before deals load. */
.ivx-deal-skel {
  background: #141414; border: 1px solid #2A2A2A; border-radius: 18px; overflow: hidden;
  contain: layout style;
}
.ivx-deal-skel-img {
  width: 100%; aspect-ratio: 16 / 10;
  background: linear-gradient(90deg, #141414 0%, #1f1f1f 50%, #141414 100%);
  background-size: 200% 100%;
  animation: ivxSkel 1.4s ease-in-out infinite;
}
.ivx-deal-skel-body { padding: 18px; }
.ivx-deal-skel-line {
  height: 12px; border-radius: 6px; margin-bottom: 10px;
  background: linear-gradient(90deg, #1a1a1a 0%, #232323 50%, #1a1a1a 100%);
  background-size: 200% 100%;
  animation: ivxSkel 1.4s ease-in-out infinite;
}
.ivx-deal-skel-line.short { width: 55%; }
.ivx-deal-skel-line.mid { width: 75%; }
.ivx-deal-skel-line.full { width: 100%; }
.ivx-deal-skel-grid {
  display: grid; gap: 20px;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
}
@media (max-width: 400px) { .ivx-deal-skel-grid { grid-template-columns: 1fr; } }

/* Prevent body scroll lock from causing a horizontal jump on desktop when the
