// Replaces every `document.body.style.overflow = 'hidden'` site-wide.
// Compensates for the scrollbar width so the page never shifts horizontally
// when a modal/signup overlay opens or closes (CLS fix).
var _ivxScrollLockDepth = 0;
function ivxScrollbarWidth() {
  try {
    if (typeof window === 'undefined' || window.innerWidth <= 0) return 0;
    return Math.max(0, window.innerWidth - document.documentElement.clientWidth);
  } catch (e) { return 0; }
}
function lockBodyScroll() {
  if (typeof document === 'undefined') return;
  if (_ivxScrollLockDepth === 0) {
    var w = ivxScrollbarWidth();
    document.documentElement.style.setProperty('--ivx-scrollbar-w', w + 'px');
    document.body.classList.add('ivx-modal-open');
  }
  _ivxScrollLockDepth++;
}
function releaseBodyScroll() {
  if (typeof document === 'undefined') return;
  if (_ivxScrollLockDepth > 0) _ivxScrollLockDepth--;
  if (_ivxScrollLockDepth === 0) {
    document.body.classList.remove('ivx-modal-open');
    document.documentElement.style.removeProperty('--ivx-scrollbar-w');
  }
}

