from html.parser import HTMLParser
class Validator(HTMLParser):
    def __init__(self):
        super().__init__()
        self.stack = []
        self.errors = []
    def handle_starttag(self, tag, attrs):
        if tag not in ['br','img','input','meta','link','hr','source','track','area','base','col','embed','param','wbr','path','circle','polyline','rect','use','stop','lineargradient','radialgradient','polygon']:
            self.stack.append(tag)
    def handle_endtag(self, tag):
        if self.stack and self.stack[-1] == tag:
            self.stack.pop()
        elif tag in self.stack:
            # pop until match
            while self.stack and self.stack[-1] != tag:
                self.stack.pop()
            if self.stack: self.stack.pop()
v = Validator()
with open('index.html') as f:
    v.feed(f.read())
print('Unclosed tags:', v.stack[-5:] if v.stack else 'NONE')
print('Validation done')
